// Fichas activas (sin soft-delete)
const fichas = $('GET Fichas').all().map(i => i.json).filter(f => f && f.id && !f.deleted_at);

// Cuenta locales por ficha (tolerante a errores: si la tabla locales
// fallara, simplemente quedan a 0).
const locales = ($('GET Locales').all() || [])
  .map(i => (i && i.json) ? i.json : i)
  .filter(l => l && l.ficha_id);

const conteo = {};
for (const l of locales) {
  conteo[l.ficha_id] = (conteo[l.ficha_id] || 0) + 1;
}

for (const f of fichas) {
  f.locales_count = conteo[f.id] || 0;
}

return [{ json: { clientes: fichas } }];

const d = $input.first().json.body;

const rawId = d.id;
const cleanId = (rawId == null || rawId === 'undefined' || rawId === 'null' || String(rawId).trim() === '') ? null : rawId;
const isEdit = !!cleanId;

const row = {};
if (isEdit) row.id = cleanId;

// Helper: en edición sólo seteamos los campos que vienen en el payload
// (clave existe, no es undefined). Antes hacíamos `row.x = d['X'] || ''`
// para todos, lo que pisaba con cadena vacía cualquier campo no enviado al
// hacer un guardado parcial (p.ej. toggle A3, marcar estado, etc.).
function set(col, ...keys) {
  for (const k of keys) {
    if (Object.prototype.hasOwnProperty.call(d, k) && d[k] !== undefined) {
      row[col] = d[k];
      return true;
    }
  }
  return false;
}

set('comercial',         'Comercial');
set('denominacion',      'Nombre Sociedad', 'Denominación Social');
set('nombre_comercial',  'Nombre Comercial');
set('calle',             'Calle');
set('numero',            'Número');
if (set('cp', 'CP')) row.cp = row.cp || null;
set('municipio',         'Municipio');
set('provincia',         'Provincia');
set('cif',               'CIF/NIF');
set('email',             'Email');
set('email_factura',     'Email Factura');
set('email_cc',          'Email CC');
set('iban',              'IBAN');
if (set('tipo_cliente',  'Tipo Cliente')) row.tipo_cliente = row.tipo_cliente || null;
set('firmas_contratadas','Firmas Contratadas');
set('jp_nombre',         'JP Nombre');
set('jp_apellidos',      'JP Apellidos');
set('jp_rol',            'JP Rol');
set('jp_telefono',       'JP Teléfono');
set('jp_mail',           'JP Mail');
set('firm_nombre',       'Firmante Nombre');
set('firm_apellidos',    'Firmante Apellidos');
set('firm_mail',         'Firmante Mail');
set('firm_dni',          'Firmante DNI');
set('firm_puesto',       'Firmante Puesto');
set('tpv',               'TPV');
set('tpv_contacto',      'TPV Contacto');
set('tpv_email',         'TPV Email');
if (Object.prototype.hasOwnProperty.call(d, 'TPV No Integrado')) row.tpv_no_integrado = d['TPV No Integrado'] === 'Sí';
set('tpv_ni_nombre',     'TPV NI Nombre');
set('tpv_ni_contacto',   'TPV NI Contacto');
set('tpv_ni_email',      'TPV NI Email');
if (Object.prototype.hasOwnProperty.call(d, 'Lite')) row.lite = (d['Lite'] === 'Sí');
set('entrega_calle',     'Entrega Calle');
set('entrega_numero',    'Entrega Número');
if (set('entrega_cp',    'Entrega CP')) row.entrega_cp = row.entrega_cp || null;
set('entrega_municipio', 'Entrega Municipio');
set('entrega_provincia', 'Entrega Provincia');
set('contacto_nombre',   'Contacto Nombre');
set('contacto_email',    'Contacto Email');
set('contacto_telefono', 'Contacto Teléfono');
if (Object.prototype.hasOwnProperty.call(d, 'Distribuidor')) row.distribuidor = (d['Distribuidor'] === 'Sí');
set('dist_empresa',      'Dist. Empresa');
set('dist_cif',          'Dist. CIF');
set('dist_direccion',    'Dist. Dirección');
set('dist_cp',           'Dist. CP');
set('dist_contacto',     'Dist. Contacto');
set('dist_mail',         'Dist. Mail');
set('dist_telefono',     'Dist. Teléfono');
if (Object.prototype.hasOwnProperty.call(d, 'Dist. Comisión Implementación (%)')) row.dist_comision = parseFloat(d['Dist. Comisión Implementación (%)']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'ImporteSetup'))               row.importe_setup = parseFloat(d['ImporteSetup']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Descuentosetup'))             row.descuento_setup = parseFloat(d['Descuentosetup']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Mensualidad Total Locales')) {
  row.mensualidad_total_locales = parseFloat(d['Mensualidad Total Locales']) || 0;
  row.mensualidad_total         = parseFloat(d['Mensualidad Total Locales']) || 0;
}
if (Object.prototype.hasOwnProperty.call(d, 'Proyecto de Implementación')) row.fin_implementacion    = parseFloat(d['Proyecto de Implementación']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Plan Producto BASIC'))        row.fin_basic             = parseFloat(d['Plan Producto BASIC']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Plan Producto PRO'))          row.fin_pro               = parseFloat(d['Plan Producto PRO']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Plan RRHH'))                  row.fin_rrhh              = parseFloat(d['Plan RRHH']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Plan Operaciones'))           row.fin_operaciones       = parseFloat(d['Plan Operaciones']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Yurest Lite'))                row.fin_lite              = parseFloat(d['Yurest Lite']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Integraciones'))              row.fin_integraciones     = parseFloat(d['Integraciones']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Mensualidad Anualizada'))     row.fin_mensualidad_anual = parseFloat(d['Mensualidad Anualizada']) || 0;

if (d.paquetes_carrito !== undefined) row.paquetes_carrito = d.paquetes_carrito;

set('cred_master',   'Credencial Master');
set('cred_yurest',   'Credencial Yurest');
set('comentarios',   'Comentarios');
set('modulos',       'Módulos');
set('baja',          'Baja');

// OJO: adjuntos y sepa_mandato son JSONB. NO hacer JSON.stringify aquí
// — el nodo Supabase volverá a serializar, guardando un string escalar
// en lugar de objeto/array. Rompe jsonb_set y el trigger asignar_sepa_ref
// con \"cannot set path in scalar\". Pasamos el valor nativo.
if (Array.isArray(d['Adjuntos'])) row.adjuntos = d['Adjuntos'];
else if (Array.isArray(d.adjuntos)) row.adjuntos = d.adjuntos;

if (d['SEPA'] && typeof d['SEPA'] === 'object') row.sepa_mandato = d['SEPA'];
else if (d.sepa_mandato && typeof d.sepa_mandato === 'object') row.sepa_mandato = d.sepa_mandato;

if (d['Estado']) row.estado = String(d['Estado']).toLowerCase();

// En alta nueva, garantizar defaults para columnas NOT NULL.
if (!isEdit) {
  if (row.denominacion == null) row.denominacion = '';
  if (row.modulos == null)      row.modulos = [];
  if (row.baja == null)         row.baja = 'No';
}

const locales = d.locales || [];

return [{ json: { row, locales, isEdit } }];

// UPDATE: extraer row para actualizar
const { row } = $input.first().json;
return [{ json: row }];

// INSERT: extraer row sin id
const { row } = $input.first().json;
delete row.id;
return [{ json: row }];

// Procesar locales: obtener ficha_id del resultado del insert/update.
// Si no hay locales devolvemos array vacío para que el siguiente nodo
// Supabase no se ejecute (antes devolvíamos un objeto con la key 'fichaId'
// que el nodo trataba como columna y rompía con
// "Could not find the 'fichaId' column of 'locales'").
const fichaResult = $input.first().json;
const fichaId = fichaResult.id;

const prepareNode = $('Preparar Ficha').first().json;
const locales = prepareNode.locales || [];

if (locales.length === 0) return [];

const rows = locales.map(l => ({
  ficha_id: fichaId,
  nombre: l.nombre || '',
  email: l.email || '',
  calle: l.calle || '',
  numero: l.numero || '',
  cp: l.cp || '',
  sociedad_cif: l.sociedad_cif || '',
  sociedad_denominacion: l.sociedad_denominacion || '',
  sociedad_calle: l.sociedad_calle || '',
  sociedad_numero: l.sociedad_numero || '',
  sociedad_cp: l.sociedad_cp || '',
  sociedad_municipio: l.sociedad_municipio || '',
  sociedad_provincia: l.sociedad_provincia || '',
  mensualidad: parseFloat(l.mensualidad) || 0
}));

return rows.map(r => ({ json: r }));
